document.querySelector(".content > form").addEventListener("submit",e=>{async function t(){const e=await fetch(`${window.location.origin}/api/push`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({long_url:document.querySelector("#pasted_url").value,expiration:document.querySelector("form .expires").getAttribute("data-selected"),user_key:null})}),t=await e.json();!0!==t.success&&console.error("Error:",t),document.querySelector(".content").classList.add("shortened"),document.querySelector("#pasted_url").value=`${window.location.origin}/#/${t.response}`}e.preventDefault(),t()}),document.addEventListener("click",e=>{e.target.closest(".expires span[data-value]")&&e.target.closest(".expires").setAttribute("data-selected",e.target.closest(".expires span[data-value]").getAttribute("data-value"))});